        string rev_s = s;
        reverse(rev_s.begin(), rev_s.end());
        string l = s + "#" + rev_s;
        vector<int> kmp = buildKMP(l);
        return rev_s.substr(0, rev_s.size() - kmp.back()) + s;
    }
private:
    vector<int> buildKMP(string s) {
        int n = s.size();
        vector<int> kmp(n, 0);
        int j = 0;
        for (int i = 1; i < n; i++) {
            while (j > 0 && s[i] != s[j]) j = kmp[j - 1];
            if (s[i] == s[j]) j++;
            kmp[i] = j;
        }
        return kmp;
    }
};
